package com.blissless.tensei.dialogsimport androidx.compose.foundation.backgroundimport androidx.compose.foundation.clickableimport androidx.compose.foundation.layout.Arrangementimport androidx.compose.foundation.layout.Boximport androidx.compose.foundation.layout.Columnimport androidx.compose.foundation.layout.Rowimport androidx.compose.foundation.layout.Spacerimport androidx.compose.foundation.layout.fillMaxHeightimport androidx.compose.foundation.layout.fillMaxSizeimport androidx.compose.foundation.layout.fillMaxWidthimport androidx.compose.foundation.layout.heightimport androidx.compose.foundation.layout.paddingimport androidx.compose.foundation.layout.sizeimport androidx.compose.foundation.layout.widthimport androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.foundation.lazy.itemsimport androidx.compose.foundation.shape.CircleShapeimport androidx.compose.foundation.shape.RoundedCornerShapeimport androidx.compose.material.icons.Iconsimport androidx.compose.material.icons.filled.Closeimport androidx.compose.material.icons.filled.Favoriteimport androidx.compose.material.icons.filled.FavoriteBorderimport androidx.compose.material3.Cardimport androidx.compose.material3.CardDefaultsimport androidx.compose.material3.Iconimport androidx.compose.material3.IconButtonimport androidx.compose.material3.MaterialThemeimport androidx.compose.material3.Textimport androidx.compose.runtime.Composableimport androidx.compose.ui.Alignmentimport androidx.compose.ui.Modifierimport androidx.compose.ui.draw.clipimport androidx.compose.ui.graphics.Colorimport androidx.compose.ui.layout.ContentScaleimport androidx.compose.ui.text.font.FontWeightimport androidx.compose.ui.text.style.TextOverflowimport androidx.compose.ui.unit.dpimport androidx.compose.ui.window.Dialogimport coil.compose.AsyncImageimport com.blissless.tensei.Rimport com.blissless.tensei.data.models.ExploreAnimeimport com.blissless.tensei.data.models.StoredFavorite@Composablefun OfflineFavoritesDialog(    favorites: Map<Int, StoredFavorite>,    isOled: Boolean,    onDismiss: () -> Unit,    onAnimeClick: (ExploreAnime) -> Unit,    onRemoveFavorite: (Int) -> Unit) {    Dialog(onDismissRequest = onDismiss) {        Card(            modifier = Modifier.fillMaxWidth().fillMaxHeight(0.85f),            shape = RoundedCornerShape(16.dp),            colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.background)        ) {            Column(modifier = Modifier.fillMaxSize()) {                Row(                    modifier = Modifier.fillMaxWidth().padding(16.dp),                    verticalAlignment = Alignment.CenterVertically                ) {                    Column {                        Text(                            "My Favorites",                            style = MaterialTheme.typography.titleLarge,                            fontWeight = FontWeight.Bold,                            color = MaterialTheme.colorScheme.onBackground                        )                        Text(                            "${favorites.size} anime (offline)",                            style = MaterialTheme.typography.bodySmall,                            color = MaterialTheme.colorScheme.onSurfaceVariant                        )                    }                    Spacer(modifier = Modifier.weight(1f))                    IconButton(onClick = onDismiss) {                        Icon(Icons.Default.Close, "Close", tint = MaterialTheme.colorScheme.onSurface)                    }                }                Box(modifier = Modifier.fillMaxSize().padding(horizontal = 16.dp, vertical = 8.dp)) {                    if (favorites.isEmpty()) {                        Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.Center) {                            Column(horizontalAlignment = Alignment.CenterHorizontally) {                                Icon(                                    Icons.Default.FavoriteBorder, contentDescription = null,                                    tint = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.5f),                                    modifier = Modifier.size(48.dp)                                )                                Spacer(Modifier.height(8.dp))                                Text("No favorites yet", color = MaterialTheme.colorScheme.onSurfaceVariant)                                Text(                                    "Tap the heart icon on anime to add them",                                    color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.7f),                                    style = MaterialTheme.typography.bodySmall                                )                            }                        }                    } else {                        LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {                            items(favorites.values.toList()) { fav ->                                OfflineFavoriteItem(                                    favorite = fav, isOled = isOled,                                    onClick = {                                        val exploreAnime = ExploreAnime(                                            id = fav.id, title = fav.title, cover = fav.cover,                                            banner = fav.banner, episodes = 0, latestEpisode = null,                                            averageScore = fav.averageScore, genres = emptyList(), year = fav.year                                        )                                        onAnimeClick(exploreAnime)                                    },                                    onRemove = { onRemoveFavorite(fav.id) }                                )                            }                        }                    }                }            }        }    }}@Composableprivate fun OfflineFavoriteItem(    favorite: StoredFavorite, isOled: Boolean,    onClick: () -> Unit, onRemove: () -> Unit) {    Card(        modifier = Modifier.fillMaxWidth().clip(RoundedCornerShape(12.dp)).clickable { onClick() },        shape = RoundedCornerShape(12.dp),        colors = CardDefaults.cardColors(containerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f))    ) {        Row(            modifier = Modifier.padding(12.dp),            verticalAlignment = Alignment.CenterVertically        ) {            Box(                modifier = Modifier                    .width(50.dp).height(70.dp)                    .clip(RoundedCornerShape(8.dp))                    .background(MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.3f))            ) {                if (favorite.cover.isNotEmpty()) {                    AsyncImage(                        model = favorite.cover, contentDescription = favorite.title,                        contentScale = ContentScale.Crop, modifier = Modifier.fillMaxSize()                    )                }            }            Spacer(Modifier.width(12.dp))            Column(Modifier.weight(1f)) {                Text(                    favorite.title.ifEmpty { "Anime" },                    style = MaterialTheme.typography.titleSmall,                    fontWeight = FontWeight.Bold,                    color = MaterialTheme.colorScheme.onBackground,                    maxLines = 2, overflow = TextOverflow.Ellipsis                )                favorite.year?.let { year ->                    Text("$year", style = MaterialTheme.typography.bodySmall, color = MaterialTheme.colorScheme.onSurfaceVariant)                }            }            IconButton(onClick = onRemove) {                Icon(                    Icons.Filled.Favorite, "Remove from favorites",                    tint = Color(0xFFFF1744), modifier = Modifier.size(24.dp)                )            }        }    }}